            c if c == b'(' as TokenKind || c == TK_STRING || c == b'{' as TokenKind => {
                // C: luaK_exp2nextreg(fs, v) — places the callee in a fixed register.
                let line = ls.linenumber;
                cg_exp_to_next_reg(ls.fs.as_mut().unwrap(), line, v)?;
                funcargs(ls, state, v)?;
            }
            _ => return Ok(()),
        }
    }
}

